#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

int solve(int n, vector<vector<int>> edges, string label) {
    vector<vector<int>> adj(n);
    for (const auto& e : edges) {
        adj[e[0]].push_back(e[1]);
        adj[e[1]].push_back(e[0]);
    }

    int max_len = 0;

    for (int start = 0; start < n; ++start) {
        vector<vector<int>> dp(n, vector<int>(1 << n, -1));
        dp[start][1 << start] = 1;

        for (int mask = 0; mask < (1 << n); ++mask) {
            for (int last = 0; last < n; ++last) {
                if (dp[last][mask] == -1) continue;

                for (int neighbor : adj[last]) {
                    if (mask & (1 << neighbor)) continue;

                    int new_mask = mask | (1 << neighbor);
                    if (label[neighbor] == label[start]) {
                        dp[neighbor][new_mask] = max(dp[neighbor][new_mask], dp[last][mask] + 1);
                    } else {
                        dp[neighbor][new_mask] = max(dp[neighbor][new_mask], dp[last][mask]);
                    }
                }
            }
        }

        for (int mask = 0; mask < (1 << n); ++mask) {
            for (int last = 0; last < n; ++last) {
                if (dp[last][mask] == -1) continue;

                int cnt = 0;
                unordered_map<char, int> freq;
                for (int i = 0; i < n; ++i) {
                    if (mask & (1 << i)) {
                        freq[label[i]]++;
                    }
                }

                bool has_odd = false;
                for (const auto& [ch, count] : freq) {
                    if (count % 2 == 1) {
                        if (has_odd) {
                            cnt = 0;
                            break;
                        }
                        has_odd = true;
                    }
                    cnt += count;
                }

                if (cnt > max_len) {
                    max_len = cnt;
                }
            }
        }
    }

    return max_len;
}

