fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let label = label.chars().collect::<Vec<_>>();
    let mut adj = vec![vec![]; n];
    for e in edges {
        let u = e[0] as usize;
        let v = e[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut max_len = 0;

    for start in 0..n {
        let mut dp = vec![vec![-1; 1 << n]; n];
        dp[start][1 << start] = 1;

        for mask in 0..(1 << n) {
            for last in 0..n {
                if dp[last][mask] == -1 {
                    continue;
                }

                for &neighbor in &adj[last] {
                    if mask & (1 << neighbor) != 0 {
                        continue;
                    }

                    let new_mask = mask | (1 << neighbor);
                    if label[neighbor] == label[start] {
                        if dp[neighbor][new_mask] < dp[last][mask] + 1 {
                            dp[neighbor][new_mask] = dp[last][mask] + 1;
                        }
                    } else {
                        if dp[neighbor][new_mask] < dp[last][mask] {
                            dp[neighbor][new_mask] = dp[last][mask];
